class Command(BaseCommand):
    help = 'Import all 50 trains from trains.js data into PostgreSQL'

    def handle(self, *args, **kwargs):
        # Delete old trains first (admin la manually add panninavai)
        old_count = Train.objects.count()
        Train.objects.all().delete()
        self.stdout.write(f'Deleted {old_count} old trains')

        created = 0
        for t in TRAINS_DATA:
            Train.objects.create(
                train_number  = t['trainNumber'],
                train_name    = t['trainName'],
                from_station  = t['from_station'],
                to_station    = t['to_station'],
                from_code     = t['fromCode'],
                to_code       = t['toCode'],
                departure_time = t['departureTime'],
                arrival_time  = t['arrivalTime'],
                duration      = t['duration'],
                train_type    = t['type'],
                classes       = t['classes'],
                fare          = t['fare'],
                total_seats   = t['totalSeats'],
                booked_seats  = t['bookedSeats'],
                seat_gender   = t['seatGender'],
                days          = t['days'],
                rating        = t['rating'],
                amenities     = t['amenities'],
            )
            created += 1

        self.stdout.write(
            self.style.SUCCESS(f'Successfully imported {created} trains into PostgreSQL!')
        )